/**
 * Starts a background job that registers IRNs for every order in `orderIds`. Each order is pre-classified (eligible / already issued / ineligible) and the result is reported in the `results` array — the worker mutates each row in-place as it advances. Idempotent: re-running with the same orderIds skips orders that already carry an active IRN.
 * @summary Register IRNs for a batch of sales orders in the background
 */
export const startBulkEinvoiceBodyOrderIdsMax = 200;



export const StartBulkEinvoiceBody = zod.object({
  "orderIds": zod.array(zod.number()).min(1).max(startBulkEinvoiceBodyOrderIdsMax)
})

export const StartBulkEinvoiceResponse = zod.void()


export const GetBulkEinvoiceBatchParams = zod.object({
  "batchId": zod.coerce.string()
})

export const GetBulkEinvoiceBatchResponse = zod.object({
  "id": zod.string(),
  "status": zod.enum(['running', 'completed']),
  "createdAt": zod.string(),
  "startedAt": zod.string().describe('Wall-clock instant the worker began processing this batch.\nFor freshly-queued batches this equals `createdAt`; the\ntwo columns diverge only if a future scheduling layer\nqueues batches before the worker picks them up.\n'),
  "completedAt": zod.string().nullable(),
  "durationMs": zod.number().nullable().describe('Wall-clock milliseconds between `startedAt` and\n`completedAt`. Null while the batch is still running so\npartial numbers can\'t be mistaken for the final tally.\n'),
  "ordersPerSecond": zod.number().nullable().describe('Achieved throughput (`processed \/ durationSeconds`,\nrounded to 1 decimal). Null while the batch is still\nrunning. Lets operators verify the bulk concurrency\nknob is actually delivering speedup against their IRP.\n'),
  "concurrency": zod.number().describe('Effective in-process worker fan-out the batch ran with —\nthe BULK_CONCURRENCY env value clamped against the\nnumber of eligible orders.\n'),
  "total": zod.number(),
  "processed": zod.number(),
  "succeeded": zod.number().describe('Rows that finished as `success` or `already_issued`.'),
  "failed": zod.number().describe('Rows that finished as `failed`.'),
  "skipped": zod.number().describe('Rows that finished as `skipped` or `ineligible`.'),
  "results": zod.array(zod.object({
  "orderId": zod.number(),
  "orderNumber": zod.string().nullable(),
  "status": zod.enum(['pending', 'running', 'success', 'already_issued', 'ineligible', 'failed', 'skipped']).describe('Lifecycle of one row inside a bulk batch.\n- `pending`: classified as eligible, the worker has not\n  reached it yet.\n- `running`: the worker is mid-flight on this row.\n- `success`: IRP accepted the invoice on this attempt.\n- `already_issued`: an active IRN already existed before\n  the batch started; nothing was re-attempted (this is\n  what makes the bulk action idempotent on retry).\n- `ineligible`: the order can never be processed in this\n  batch (wrong status, missing buyer GSTIN, etc.).\n- `failed`: the IRP rejected this attempt; the operator\n  can re-run the batch on just the failures.\n- `skipped`: another in-flight attempt held the claim, or\n  the IRN was previously cancelled at the IRP.\n'),
  "message": zod.string().nullable(),
  "errorCode": zod.string().nullable(),
  "irn": zod.string().nullable().describe('IRP-issued Invoice Reference Number for rows that ended\nas `success` or `already_issued`. Null on every other\nstatus. Carrying the IRN in its own field (rather than\nforcing the UI to parse it out of the message) means the\nCSV export can show the existing IRN even on rows that\nwere already registered before this batch began.\n'),
  "ackNumber": zod.string().nullable().describe('IRP acknowledgement number that pairs with `irn`. Null\non rows that did not receive (or already had) an IRN.\n'),
  "ackDate": zod.string().nullable().describe('ISO timestamp the IRN was acknowledged at the IRP. Null\non rows that did not receive (or already had) an IRN.\n')
}))
})


